#include <iostream>
#include <cstring>
using namespace std;
int main()
{
    string s;
    int count1 = 0, count2 = 0;
    getline(cin, s);
    for (int i = 0; i <= s.size() - 3; i++)
    {
        if (s[i] == 'b' || s[i + 1] == 'o' || s[i + 2] == 'y')
        {
            count1 += 1;
        }
    }
    for (int i = 0; i <= s.size() - 4; i++)
    {
        if (s[i] == 'g' || s[i + 1] == 'i' || s[i + 2] == 'r' || s[i + 3] == 'l')
        {
            count2 += 1;
        }
    }
    cout << count1 << endl << count2;
    return 0;
}
